import React from "react";

function Hero() {
  return (
    <div className="text-white flex flex-col items-center justify-center h-[80vh] text-center">
      <h1 className="text-5xl font-bold mb-4">
        AI Powered Recruitment Platform
      </h1>

      <p className="text-gray-300 max-w-xl">
        HIRETRAX helps companies find the best talent using AI-driven matching,
        smart filtering, and modern recruitment tools.
      </p>

      <button className="mt-6 bg-blue-500 px-6 py-3 rounded-xl hover:bg-blue-600">
        Start Hiring
      </button>
    </div>
  );
}

export default Hero;
